import { Registry } from '../core/zc-registry';

export let LegendRegistry = {
    add: component => {
        let { encode, view } = component;
        Registry.setComponent(_key(encode, view), component);
    },
    get: (encode, view) => Registry.getComponent(_key(encode, view))
};

function _key(encode, view) {
    return `legend-${encode}-${view}`;
}
